// We natively glue '.isEven()' seamlessly onto the core Int!
fun Int.isEven(): Boolean {
    // 'this' strictly refers specifically to the exact number actively utilizing it
    return this % 2 == 0
}

fun main() {
    val myNumber = 40
    // It feels natively built-in natively!
    println(myNumber.isEven()) // Prints: true
    println(17.isEven())       // Prints: false
}
